-- =====================================================
-- TREE_NODE 테이블
-- =====================================================
CREATE TABLE TREE_NODE (
    ID         NUMBER        NOT NULL,
    NODE_KEY   VARCHAR2(50)  NOT NULL,
    NODE_NAME  VARCHAR2(100) NOT NULL,
    PARENT_KEY VARCHAR2(50),
    LEVEL_NO   NUMBER        DEFAULT 1 NOT NULL,
    SORT_ORDER NUMBER        DEFAULT 0 NOT NULL,
    CREATED_AT TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT PK_TREE_NODE PRIMARY KEY (ID),
    CONSTRAINT UQ_TREE_NODE_KEY UNIQUE (NODE_KEY)
);

CREATE SEQUENCE TREE_NODE_SEQ START WITH 1 INCREMENT BY 1 NOCACHE;

-- =====================================================
-- GRID_ITEM 테이블
-- =====================================================
CREATE TABLE GRID_ITEM (
    ID         NUMBER        NOT NULL,
    NODE_KEY   VARCHAR2(50)  NOT NULL,
    COL1       VARCHAR2(100),
    COL2       VARCHAR2(100),
    COL3       VARCHAR2(100),
    COL4       VARCHAR2(100),
    COL5       VARCHAR2(100),
    CREATED_AT TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT PK_GRID_ITEM PRIMARY KEY (ID)
);

CREATE SEQUENCE GRID_ITEM_SEQ START WITH 1 INCREMENT BY 1 NOCACHE;

